{
  "title": "डिफ़ॉल्ट मान",
  "group": "मानक इनपुट/आउटपुट",
  "options": [],
  "questionProse": [
    "त्रुटि आउटपुट को मानक आउटपुट में संयोजित करने के लिए किस ऑपरेटर का उपयोग किया जाता है?"
  ],
  "questionCode": [],
  "explanationProse": [
    "`2>&1` ऑपरेटर मानक त्रुटि (फ़ाइल डिस्क्रिप्टर 2) को मानक आउटपुट (फ़ाइल डिस्क्रिप्टर 1) पर रीडायरेक्ट करता है। यह त्रुटि संदेशों को सामान्य आउटपुट के साथ एक ही आउटपुट स्ट्रीम में कैप्चर करने के लिए उपयोगी है।\n\n    `1>&2` ऑपरेटर मानक आउटपुट को मानक त्रुटि पर रीडायरेक्ट करता है, हालांकि, प्रश्न पूछा गया था कि मानक त्रुटि को मानक आउटपुट पर कैसे रीडायरेक्ट किया जाए।\n\n    अधिक जानने के लिए कि अंदर क्या हो रहा है, [ग्रेग का उत्कृष्ट रीडायरेक्शन FAQ](https://mywiki.wooledge.org/BashFAQ/055) देखें।\n\n    साथ ही, सुझाए गए कॉपी सुधारों के लिए Reddit उपयोगकर्ता [u/OneTurnMore](https://www.reddit.com/user/OneTurnMore/) का धन्यवाद।"
  ],
  "explanationCode": []
}
